22	
23		if (queue->compare)
24			BUG("prio_queue_reverse() on non-LIFO queue");
25		if (!queue->nr)
26			return;
27		for (i = 0; i < (j = (queue->nr - 1) - i); i++)
28			swap(queue, i, j);
29	}
