4600	{
4601		struct commit *c;
4602		int max_count = revs->max_count;
4603		int queuei_count = 0;
4604		int queueo_count = 0;
4605		struct commit_list *queueo = NULL;
4606		struct commit_list *queuei = NULL;
4607		struct commit_list *reversed_queue = NULL;
4608		struct commit_list *p;
4609	
