4614			 * It is fine to do, get_revision_internal() doesn't consider
4615			 * children commits as they have been already processed and the
4616			 * traversal happens only child to parent.
4617			 *
4618			 * We do this because the --graph machinery relies on the status
4619			 * of the parents to decide how the printing will happen.
4620			 *
4621			 * We can't simply replace this instruction with a
4622			 * graph_update() as it doesn't do the actualy printing, we'd
4623			 * have to remove any commit that goes over the
4624			 * --max-count-oldest limit from revs->graph.
4625			 */
4626			c->object.flags &= ~(SHOWN | CHILD_SHOWN);
4627			commit_list_insert(c, &queuei);
4628			if (!(c->object.flags & BOUNDARY))
4629				queuei_count++;
4630			while (queuei_count + queueo_count > max_count) {
4631				if (!queueo_count) {
4632					while ((c = pop_commit(&queuei))) {
4633						commit_list_insert(c, &queueo);
4634						queueo_count++;
4635					}
4636					queuei_count = 0;
4637				}
4638				c = pop_commit(&queueo);
4639				queueo_count--;
4640				/* We need to do this otherwise we'll discard the
4641				 * commits that go over the --max-count-oldest limit but
4642				 * not their respective boundaries. This matters only if
4643				 * we're discarding the commit right before the boundary.
4644				 */
4645				for (p = c->parents; p; p = p->next)
4646					p->item->object.flags &= ~CHILD_SHOWN;
4647			}
4648		}
4649	
4650		while ((c = pop_commit(&queueo)))
4651			commit_list_insert(c, &reversed_queue);
4652		while ((c = pop_commit(&queuei)))
4653			commit_list_insert(c, &queueo);
4654		while ((c = pop_commit(&queueo)))
4655			commit_list_insert(c, &reversed_queue);
4656	
4657		while ((c = pop_commit(&reversed_queue)))
4658			commit_list_insert(c, queue);
4659	}
