4669			retrieve_oldest_commits(revs, &queue);
4670			commit_list_free(revs->commits);
4671			revs->commits = queue;
4672			revs->max_count_stage = 1;
4673		}
4674	
4675		if (revs->reverse) {
4676			reversed = NULL;
4677			if (revs->max_count_type == 1)
4678				while ((c = pop_commit(&revs->commits)))
4679					commit_list_insert(c, &reversed);
4680			else
4681				while ((c = get_revision_internal(revs)))
4682					commit_list_insert(c, &reversed);
4683			commit_list_free(revs->commits);
4684			revs->commits = reversed;
4685			revs->reverse = 0;
4686			revs->reverse_output_stage = 1;
4687		}
4688	
