4695	
4696		if (revs->max_count_stage) {
4697			c = pop_commit(&revs->commits);
4698			if (c) {
4699				c->object.flags |= SHOWN;
4700				if (!(c->object.flags & BOUNDARY))
4701					for (p = c->parents; p; p = p->next)
4702						p->item->object.flags |= CHILD_SHOWN;
