4721			return "-";
4722		else if (commit->object.flags & UNINTERESTING)
4723			return "^";
4724		else if (commit->object.flags & PATCHSAME)
4725			return "=";
4726		else if (!revs || revs->left_right) {
4727			if (commit->object.flags & SYMMETRIC_LEFT)
4728				return "<";
4729			else
4730				return ">";
4731		} else if (revs->graph)
4732			return "*";
4733		else if (revs->cherry_mark)
